def _outage_size_cap(model, t):
    return sum(model.x[l, j, i, t] for (l, j) in model.K for i in model.I) <= 15
model.outage_size_cap = Constraint(model.T, rule=_outage_size_cap)

def _spacing(model, t):
    if t + 3 > len(model.T):
        return Constraint.Skip
    return sum(model.o[ft] for ft in [t, t + 1, t + 2, t + 3]) <= 1
model.min_spacing = Constraint(model.T, rule=_spacing)
